118	  /** Parses:  <factor>   ::= <prim> | <variable> | ( <exp> )
119	    * @param token   first token in input stream to be parsed; remainder in Lexer named in.
120	    */
121	  private AST parseFactor(Token token) {
122	    
123	    if (token == LeftParen.ONLY) { 
124	      /* Parse a parenthesized expression */
125	      AST exp = parseExp();
126	      token = in.readToken();
127	      if (token != RightParen.ONLY) error(token,"`)'");
128	      return exp;
129	    }
130	    
131	    if (! (token instanceof PrimFun) && ! (token instanceof Variable))
132	      error(token,"constant, primitive, variable, or `('");
133	    
134	    // Term = Variable or PrimFun       
135	    return (Term) token;
136	  }      
