138	  /** Parses `if <exp> then <exp> else <exp>' given that `if' has already been read. */
139	  private AST parseIf() {
140	    
141	    AST test = parseExp();
142	    Token key1 = in.readToken();
143	    if (key1 != Lexer.THEN) error(key1,"`then'");
144	    AST conseq = parseExp();
145	    Token key2 = in.readToken();
146	    if (key2 != Lexer.ELSE) error(key2,"`else'");
147	    AST alt = parseExp();
148	    return new If(test,conseq,alt);
149	  }
