180	    *  <empty> ::=
181	    *  <prop-exp-list> ::= <exp> | <exp> <separator> <prop-exp-list> 
182	    */
183	  private AST[] parseExps(Token separator, Token delim) {
184	    
185	    LinkedList<AST> exps = new LinkedList<AST>();
186	    Token next = in.peek();
187	    
188	    if (next == delim) {
189	      in.readToken(); // consume RightParen
190	      return new AST[0];
191	    }
192	    
193	    // next is still at front of input stream
194	    
195	    do {
196	      AST exp = parseExp();
197	      exps.addLast(exp);
198	      next = in.readToken();
199	    } while (next == separator);
200	    
201	    if (next != delim) error(next,"`,' or `)'");
202	    return (AST[]) exps.toArray(new AST[0]);
203	  }
